// ConversationService.js — Manages saved Claude chat conversations
// CommonJS module. Stores conversations as JSON files in {ROOT}/conversations/

const fs = require('fs');
const path = require('path');
const { CONVERSATIONS_DIR } = require('../../src/server/utils/constants');

function ensureDir() {
  fs.mkdirSync(CONVERSATIONS_DIR, { recursive: true });
}

/**
 * Returns array of {id, name, created, updated, messageCount} sorted newest-first by updated.
 */
function listConversations() {
  try {
    ensureDir();
    const files = fs.readdirSync(CONVERSATIONS_DIR).filter(f => f.endsWith('.json'));
    const results = [];
    for (const file of files) {
      try {
        const raw = fs.readFileSync(path.join(CONVERSATIONS_DIR, file), 'utf8');
        const conv = JSON.parse(raw);
        results.push({
          id: conv.id,
          name: conv.name,
          created: conv.created,
          updated: conv.updated,
          messageCount: Array.isArray(conv.messages) ? conv.messages.length : 0,
        });
      } catch (e) {
        // Skip malformed files
      }
    }
    results.sort((a, b) => new Date(b.updated) - new Date(a.updated));
    return results;
  } catch (e) {
    return [];
  }
}

/**
 * Returns full conversation object {id, name, created, updated, messages:[]} or null.
 */
function loadConversation(id) {
  try {
    const filePath = path.join(CONVERSATIONS_DIR, `${id}.json`);
    const raw = fs.readFileSync(filePath, 'utf8');
    return JSON.parse(raw);
  } catch (e) {
    return null;
  }
}

/**
 * Writes conversation data to disk. Returns saved data or null on error.
 */
function saveConversation(data) {
  try {
    ensureDir();
    const toSave = { ...data, updated: new Date().toISOString() };
    const filePath = path.join(CONVERSATIONS_DIR, `${toSave.id}.json`);
    fs.writeFileSync(filePath, JSON.stringify(toSave, null, 2), 'utf8');
    return toSave;
  } catch (e) {
    return null;
  }
}

/**
 * Creates a new named conversation, saves it to disk, and returns it.
 * If name is not provided, defaults to 'Session {count+1}'.
 */
function createConversation(name) {
  try {
    ensureDir();
    let count = 0;
    try {
      count = fs.readdirSync(CONVERSATIONS_DIR).filter(f => f.endsWith('.json')).length;
    } catch (e) {
      count = 0;
    }
    const now = new Date().toISOString();
    const conv = {
      id: 'conv_' + Date.now(),
      name: name || ('Session ' + (count + 1)),
      created: now,
      updated: now,
      messages: [],
    };
    const filePath = path.join(CONVERSATIONS_DIR, `${conv.id}.json`);
    fs.writeFileSync(filePath, JSON.stringify(conv, null, 2), 'utf8');
    return conv;
  } catch (e) {
    return { error: e.message };
  }
}

/**
 * Deletes the conversation file for the given id.
 * Returns {success: true} or {error: message}.
 */
function deleteConversation(id) {
  try {
    const filePath = path.join(CONVERSATIONS_DIR, `${id}.json`);
    fs.unlinkSync(filePath);
    return { success: true };
  } catch (e) {
    return { error: e.message };
  }
}

/**
 * Renames a conversation. Returns updated conversation or {error: message}.
 */
function renameConversation(id, name) {
  try {
    const conv = loadConversation(id);
    if (!conv) {
      return { error: `Conversation not found: ${id}` };
    }
    const updated = saveConversation({ ...conv, name });
    if (!updated) {
      return { error: 'Failed to save renamed conversation' };
    }
    return updated;
  } catch (e) {
    return { error: e.message };
  }
}

module.exports = {
  listConversations,
  loadConversation,
  saveConversation,
  createConversation,
  deleteConversation,
  renameConversation,
};

const path = require('path');

const PORT = process.env.PORT || 3456;
const ROOT = path.resolve(__dirname, '..', '..', '..');
const DASHBOARDS_DIR = path.join(ROOT, 'dashboards');
const QUEUE_DIR = path.join(ROOT, 'queue');
const ARCHIVE_DIR = path.join(ROOT, 'Archive');
const HISTORY_DIR = path.join(ROOT, 'history');
const CONVERSATIONS_DIR = path.join(ROOT, 'conversations');
const PUBLIC_DIR = path.join(ROOT, 'public');

// --- Named Constants ---
const INIT_POLL_MS = 100;           // fs.watchFile polling interval for initialization.json and logs.json
const PROGRESS_RETRY_MS = 80;       // Retry delay for reading progress files that may be mid-write
const PROGRESS_READ_DELAY_MS = 30;  // Initial delay before reading a changed progress file
const RECONCILE_DEBOUNCE_MS = 300;  // Debounce interval for reconciling dashboard directory changes
const HEARTBEAT_MS = 15000;         // SSE heartbeat ping interval

const MIME_TYPES = {
  '.html': 'text/html',
  '.css': 'text/css',
  '.js': 'application/javascript',
  '.json': 'application/json',
};

const DEFAULT_INITIALIZATION = { task: null, agents: [], waves: [], chains: [], history: [] };
const DEFAULT_LOGS = { entries: [] };

module.exports = {
  PORT,
  ROOT,
  DASHBOARDS_DIR,
  QUEUE_DIR,
  ARCHIVE_DIR,
  HISTORY_DIR,
  CONVERSATIONS_DIR,
  PUBLIC_DIR,
  INIT_POLL_MS,
  PROGRESS_RETRY_MS,
  PROGRESS_READ_DELAY_MS,
  RECONCILE_DEBOUNCE_MS,
  HEARTBEAT_MS,
  MIME_TYPES,
  DEFAULT_INITIALIZATION,
  DEFAULT_LOGS,
};

// electron/ipc-handlers.js — IPC Data Bridge
// Registers all IPC handlers, bridging existing server services to the Electron renderer.
// Sets up file watchers that push real-time updates via webContents.send().

const { ipcMain } = require('electron');
const fs = require('fs');
const path = require('path');

// Import existing services (CommonJS — paths resolve relative to the required file)
const {
  listDashboards,
  ensureDashboard,
  getDashboardDir,
  readDashboardInit,
  readDashboardLogs,
  readDashboardProgress,
  readDashboardInitAsync,
  readDashboardLogsAsync,
  readDashboardProgressAsync,
  clearDashboardProgress,
  copyDirSync,
} = require('../src/server/services/DashboardService');

const {
  watchDashboard,
  startDashboardsWatcher,
  startQueueWatcher,
  stopAll: stopAllWatchers,
} = require('../src/server/services/WatcherService');

const {
  listArchives,
  archiveDashboard,
  deleteArchive,
} = require('../src/server/services/ArchiveService');

const {
  listHistory,
  buildHistorySummary,
  saveHistorySummary,
} = require('../src/server/services/HistoryService');

const {
  listQueueSummaries,
  getQueueDir,
  readQueueInitAsync,
  readQueueLogsAsync,
  readQueueProgressAsync,
} = require('../src/server/services/QueueService');

const {
  listConversations,
  loadConversation,
  saveConversation,
  deleteConversation,
  renameConversation,
} = require('./services/ConversationService');

const { readJSONAsync } = require('../src/server/utils/json');

const {
  DASHBOARDS_DIR,
  QUEUE_DIR,
  ARCHIVE_DIR,
  HISTORY_DIR,
  DEFAULT_INITIALIZATION,
  DEFAULT_LOGS,
} = require('../src/server/utils/constants');

const fsPromises = fs.promises;

// ---------------------------------------------------------------------------
// Broadcast bridge — adapts WatcherService's broadcastFn to IPC
// ---------------------------------------------------------------------------

/**
 * Create a broadcast function that sends events to the renderer via IPC.
 * Checks that the window exists and is not destroyed before sending.
 *
 * @param {Function} getMainWindow - returns the BrowserWindow instance
 * @returns {Function} broadcastFn(eventName, data)
 */
function createBroadcastFn(getMainWindow) {
  return function broadcast(eventName, data) {
    const win = getMainWindow();
    if (win && !win.isDestroyed()) {
      win.webContents.send(eventName, data);
    }

    // Feed progress updates to the SwarmOrchestrator for dispatch loop
    if (eventName === 'agent_progress' && data && data.task_id && data.dashboardId) {
      try {
        const SwarmOrchestrator = require('./services/SwarmOrchestrator');
        SwarmOrchestrator.handleProgressUpdate(data.dashboardId, data.task_id, data);
      } catch (e) { /* orchestrator not initialized yet */ }
    }
  };
}

// ---------------------------------------------------------------------------
// Status computation — shared logic (mirrors apiRoutes.js)
// ---------------------------------------------------------------------------

/**
 * Derive a dashboard's status from its initialization and progress data.
 *
 * @param {Object|null} init - parsed initialization.json
 * @param {Object} progress - keyed by task_id
 * @returns {string} 'idle' | 'in_progress' | 'completed' | 'error'
 */
function deriveDashboardStatus(init, progress) {
  const hasTask = init && init.task && init.task.name;
  if (!hasTask) return 'idle';

  const progressValues = Object.values(progress);
  if (progressValues.length === 0) return 'in_progress';

  let allDone = true;
  let hasFailed = false;
  let hasInProgress = false;
  for (const p of progressValues) {
    if (p.status === 'in_progress') hasInProgress = true;
    if (p.status === 'failed') hasFailed = true;
    if (p.status !== 'completed' && p.status !== 'failed') allDone = false;
  }

  const totalTasks = (init.task && init.task.total_tasks) || 0;
  if (totalTasks > 0 && progressValues.length < totalTasks) allDone = false;

  if (allDone && hasFailed) return 'error';
  if (allDone) return 'completed';
  if (hasInProgress || progressValues.length > 0) return 'in_progress';
  return 'idle';
}

// ---------------------------------------------------------------------------
// Directory initialization — mirrors server startup()
// ---------------------------------------------------------------------------

/**
 * Ensure all required directories and default dashboards exist.
 */
function ensureDirectories() {
  if (!fs.existsSync(DASHBOARDS_DIR)) {
    fs.mkdirSync(DASHBOARDS_DIR, { recursive: true });
  }

  for (let i = 1; i <= 5; i++) {
    ensureDashboard(`dashboard${i}`);
  }

  if (!fs.existsSync(ARCHIVE_DIR)) {
    fs.mkdirSync(ARCHIVE_DIR, { recursive: true });
  }
  if (!fs.existsSync(HISTORY_DIR)) {
    fs.mkdirSync(HISTORY_DIR, { recursive: true });
  }
  if (!fs.existsSync(QUEUE_DIR)) {
    fs.mkdirSync(QUEUE_DIR, { recursive: true });
  }
}

// ---------------------------------------------------------------------------
// IPC Handler registration
// ---------------------------------------------------------------------------

/**
 * Register all IPC handlers and start file watchers.
 * Called once from main.js during app initialization.
 *
 * @param {Function} getMainWindow - returns the BrowserWindow (may be null during startup)
 */
function registerIPCHandlers(getMainWindow) {
  const broadcastFn = createBroadcastFn(getMainWindow);

  // --- 1. Ensure directories exist ---
  ensureDirectories();

  // --- 2. Register all ipcMain.handle() handlers ---

  // GET /api/dashboards -> get-dashboards
  ipcMain.handle('get-dashboards', async () => {
    return { dashboards: listDashboards() };
  });

  // GET /api/dashboards/statuses -> get-dashboard-statuses
  ipcMain.handle('get-dashboard-statuses', async () => {
    const dashboards = listDashboards();
    const statuses = {};
    for (const id of dashboards) {
      const init = readDashboardInit(id);
      const progress = readDashboardProgress(id);
      statuses[id] = deriveDashboardStatus(init, progress);
    }
    return { statuses };
  });

  // GET /api/overview -> get-overview
  ipcMain.handle('get-overview', async () => {
    const dashboards = listDashboards();
    const dashboardSummaries = [];
    const allLogEntries = [];

    for (const id of dashboards) {
      const init = readDashboardInit(id);
      const progress = readDashboardProgress(id);
      const hasTask = init && init.task && init.task.name;
      const status = deriveDashboardStatus(init, progress);

      let taskSummary = null;
      if (hasTask) {
        const progressValues = Object.values(progress);
        let completedCount = 0;
        let failedCount = 0;
        for (const p of progressValues) {
          if (p.status === 'completed') completedCount++;
          if (p.status === 'failed') failedCount++;
        }
        taskSummary = {
          name: init.task.name,
          type: init.task.type || null,
          directory: init.task.directory || null,
          total_tasks: init.task.total_tasks || (init.agents ? init.agents.length : 0),
          completed_tasks: completedCount,
          failed_tasks: failedCount,
          created: init.task.created || null,
        };
      }

      dashboardSummaries.push({ id, status, task: taskSummary });

      if (hasTask) {
        const logs = readDashboardLogs(id);
        if (logs && logs.entries) {
          for (const entry of logs.entries) {
            allLogEntries.push(Object.assign({ dashboardId: id }, entry));
          }
        }
      }
    }

    // Sort logs newest-first, take top 30
    allLogEntries.sort((a, b) => (b.timestamp || '').localeCompare(a.timestamp || ''));
    const recentLogs = allLogEntries.slice(0, 30);

    const archives = listArchives().slice(0, 10);
    const history = listHistory().slice(0, 10);

    return { dashboards: dashboardSummaries, archives, history, recentLogs };
  });

  // GET /api/dashboards/:id/initialization -> get-dashboard-init
  ipcMain.handle('get-dashboard-init', async (_event, id) => {
    const data = await readDashboardInitAsync(id);
    return data || { ...DEFAULT_INITIALIZATION };
  });

  // GET /api/dashboards/:id/logs -> get-dashboard-logs
  ipcMain.handle('get-dashboard-logs', async (_event, id) => {
    const data = await readDashboardLogsAsync(id);
    return data || { ...DEFAULT_LOGS };
  });

  // GET /api/dashboards/:id/progress -> get-dashboard-progress
  ipcMain.handle('get-dashboard-progress', async (_event, id) => {
    return await readDashboardProgressAsync(id);
  });

  // POST /api/dashboards/:id/clear -> clear-dashboard
  ipcMain.handle('clear-dashboard', async (_event, id) => {
    // Build and save history summary before clearing
    const init = readDashboardInit(id);
    if (init && init.task && init.task.name) {
      const summary = buildHistorySummary(id);
      if (!fs.existsSync(HISTORY_DIR)) {
        fs.mkdirSync(HISTORY_DIR, { recursive: true });
      }
      const today = new Date().toISOString().slice(0, 10);
      const historyFile = path.join(HISTORY_DIR, `${today}_${summary.task_name}.json`);
      fs.writeFileSync(historyFile, JSON.stringify(summary, null, 2));
    }

    // Reset dashboard
    const dashboardDir = getDashboardDir(id);
    ensureDashboard(id);
    clearDashboardProgress(id);
    const initFile = path.join(dashboardDir, 'initialization.json');
    const logsFile = path.join(dashboardDir, 'logs.json');
    fs.writeFileSync(initFile, JSON.stringify(DEFAULT_INITIALIZATION, null, 2));
    fs.writeFileSync(logsFile, JSON.stringify(DEFAULT_LOGS, null, 2));

    return { success: true };
  });

  // POST /api/dashboards/:id/archive -> archive-dashboard
  ipcMain.handle('archive-dashboard', async (_event, id) => {
    const dashboardDir = getDashboardDir(id);
    const init = readDashboardInit(id);
    const taskName = (init && init.task && init.task.name) ? init.task.name : 'unnamed';
    const today = new Date().toISOString().slice(0, 10);
    const archiveName = `${today}_${taskName}`;
    const archiveDir = path.join(ARCHIVE_DIR, archiveName);

    // Copy dashboard contents to archive
    try {
      copyDirSync(dashboardDir, archiveDir);
    } catch (err) {
      return { success: false, error: 'Failed to archive: ' + err.message };
    }

    // Clear the dashboard after archiving
    ensureDashboard(id);
    clearDashboardProgress(id);
    const initFile = path.join(dashboardDir, 'initialization.json');
    const logsFile = path.join(dashboardDir, 'logs.json');
    fs.writeFileSync(initFile, JSON.stringify(DEFAULT_INITIALIZATION, null, 2));
    fs.writeFileSync(logsFile, JSON.stringify(DEFAULT_LOGS, null, 2));

    return { success: true, archiveName };
  });

  // POST /api/dashboards/:id/save-history -> save-dashboard-history
  ipcMain.handle('save-dashboard-history', async (_event, id) => {
    const init = readDashboardInit(id);
    if (!init || !init.task || !init.task.name) {
      return { success: false, error: 'No active task to save history for' };
    }
    const summary = buildHistorySummary(id);
    if (!fs.existsSync(HISTORY_DIR)) {
      fs.mkdirSync(HISTORY_DIR, { recursive: true });
    }
    const today = new Date().toISOString().slice(0, 10);
    const safeName = summary.task_name.replace(/[^a-zA-Z0-9_-]/g, '_');
    const historyFile = path.join(HISTORY_DIR, `${today}_${safeName}.json`);
    // Prevent duplicates
    if (fs.existsSync(historyFile)) {
      return { success: true, alreadySaved: true, task_name: summary.task_name };
    }
    fs.writeFileSync(historyFile, JSON.stringify(summary, null, 2));
    return { success: true, task_name: summary.task_name };
  });

  // GET /api/dashboards/:id/export -> export-dashboard
  ipcMain.handle('export-dashboard', async (_event, id) => {
    const initialization = (await readDashboardInitAsync(id)) || { ...DEFAULT_INITIALIZATION };
    const logs = (await readDashboardLogsAsync(id)) || { ...DEFAULT_LOGS };
    const progress = await readDashboardProgressAsync(id);
    const summary = buildHistorySummary(id);
    // Remove cleared_at — only relevant when actually clearing
    delete summary.cleared_at;

    return {
      exported_at: new Date().toISOString(),
      summary,
      initialization,
      logs,
      progress,
    };
  });

  // GET /api/archives -> get-archives
  ipcMain.handle('get-archives', async () => {
    return { archives: listArchives() };
  });

  // GET /api/archives/:name -> get-archive
  ipcMain.handle('get-archive', async (_event, name) => {
    const archiveDir = path.join(ARCHIVE_DIR, name);
    if (!fs.existsSync(archiveDir)) {
      return { error: 'Archive not found' };
    }
    const initialization = (await readJSONAsync(path.join(archiveDir, 'initialization.json'))) || { ...DEFAULT_INITIALIZATION };
    const logs = (await readJSONAsync(path.join(archiveDir, 'logs.json'))) || { ...DEFAULT_LOGS };
    const progress = {};
    const progressDir = path.join(archiveDir, 'progress');
    try {
      const files = await fsPromises.readdir(progressDir);
      const reads = files.filter(f => f.endsWith('.json')).map(async (file) => {
        const data = await readJSONAsync(path.join(progressDir, file));
        if (data && data.task_id) progress[data.task_id] = data;
      });
      await Promise.all(reads);
    } catch { /* progress dir may not exist */ }
    return { initialization, logs, progress };
  });

  // DELETE /api/archives/:name -> delete-archive
  ipcMain.handle('delete-archive', async (_event, name) => {
    const deleted = deleteArchive(name);
    if (!deleted) {
      return { success: false, error: 'Archive not found' };
    }
    return { success: true };
  });

  // GET /api/history -> get-history
  ipcMain.handle('get-history', async () => {
    return { history: listHistory() };
  });

  // GET /api/queue -> get-queue
  ipcMain.handle('get-queue', async () => {
    return { queue: listQueueSummaries() };
  });

  // GET /api/queue/:id -> get-queue-item
  ipcMain.handle('get-queue-item', async (_event, queueId) => {
    const queueDir = getQueueDir(queueId);
    if (!fs.existsSync(queueDir)) {
      return { error: 'Queue item not found' };
    }
    const initialization = (await readQueueInitAsync(queueId)) || { ...DEFAULT_INITIALIZATION };
    const logs = (await readQueueLogsAsync(queueId)) || { ...DEFAULT_LOGS };
    const progress = await readQueueProgressAsync(queueId);
    return { initialization, logs, progress };
  });

  // --- Settings handlers ---
  ipcMain.handle('get-settings', async () => {
    const settings = require('./settings');
    return settings.getAll();
  });

  ipcMain.handle('set-setting', async (_event, key, value) => {
    const settings = require('./settings');
    settings.set(key, value);
    return { success: true };
  });

  ipcMain.handle('reset-settings', async () => {
    const settings = require('./settings');
    return settings.reset();
  });

  // --- Project handlers ---
  const ProjectService = require('./services/ProjectService');
  const { dialog } = require('electron');

  ipcMain.handle('select-project-directory', async () => {
    const win = getMainWindow();
    const result = await dialog.showOpenDialog(win, {
      properties: ['openDirectory'],
      title: 'Select Project Directory',
    });
    if (result.canceled || result.filePaths.length === 0) return null;
    return result.filePaths[0];
  });

  ipcMain.handle('load-project', async (_event, dirPath) => {
    return ProjectService.loadProject(dirPath);
  });

  ipcMain.handle('get-recent-projects', async () => {
    const settings = require('./settings');
    return settings.get('recentProjects') || [];
  });

  ipcMain.handle('add-recent-project', async (_event, project) => {
    const settings = require('./settings');
    var recents = settings.get('recentProjects') || [];
    // Remove duplicate
    recents = recents.filter(function (p) { return p.path !== project.path; });
    recents.unshift({ path: project.path, name: project.name, lastOpened: new Date().toISOString() });
    if (recents.length > 10) recents = recents.slice(0, 10);
    settings.set('recentProjects', recents);
    return recents;
  });

  ipcMain.handle('get-project-context', async (_event, dirPath) => {
    return ProjectService.getProjectContext(dirPath);
  });

  ipcMain.handle('scan-project-directory', async (_event, dirPath, depth) => {
    return ProjectService.scanDirectory(dirPath, depth || 2);
  });

  ipcMain.handle('detect-claude-cli', async () => {
    return ProjectService.detectClaudeCLI();
  });

  // --- Task Editor handlers ---
  const TaskEditorService = require('./services/TaskEditorService');

  ipcMain.handle('create-swarm', async (_event, dashboardId, opts) => {
    return TaskEditorService.createSwarm(dashboardId, opts);
  });

  ipcMain.handle('add-task', async (_event, dashboardId, task) => {
    return TaskEditorService.addTask(dashboardId, task);
  });

  ipcMain.handle('update-task', async (_event, dashboardId, taskId, updates) => {
    return TaskEditorService.updateTask(dashboardId, taskId, updates);
  });

  ipcMain.handle('remove-task', async (_event, dashboardId, taskId) => {
    return TaskEditorService.removeTask(dashboardId, taskId);
  });

  ipcMain.handle('add-wave', async (_event, dashboardId, wave) => {
    return TaskEditorService.addWave(dashboardId, wave);
  });

  ipcMain.handle('remove-wave', async (_event, dashboardId, waveId) => {
    return TaskEditorService.removeWave(dashboardId, waveId);
  });

  ipcMain.handle('next-task-id', async (_event, dashboardId, waveNum) => {
    return TaskEditorService.nextTaskId(dashboardId, waveNum);
  });

  ipcMain.handle('validate-dependencies', async (_event, dashboardId) => {
    return TaskEditorService.validateDependencies(dashboardId);
  });

  // --- Worker handlers ---
  const ClaudeCodeService = require('./services/ClaudeCodeService');
  ClaudeCodeService.init(broadcastFn);

  // Build system prompt for ClaudeView chat — reads Synapse CLAUDE.md + project CLAUDE.md
  ipcMain.handle('get-chat-system-prompt', async (_event, projectDir) => {
    const parts = [];

    // Read Synapse CLAUDE.md
    const synapseClaudeMd = path.join(path.resolve(__dirname, '..'), 'CLAUDE.md');
    try {
      const content = fs.readFileSync(synapseClaudeMd, 'utf-8');
      parts.push('# Synapse Context\n' + content);
    } catch (e) { /* ignore */ }

    // Read project CLAUDE.md if available
    if (projectDir) {
      const projectClaudeMd = path.join(projectDir, 'CLAUDE.md');
      try {
        const content = fs.readFileSync(projectClaudeMd, 'utf-8');
        parts.push('\n# Project Context\n' + content);
      } catch (e) { /* ignore */ }

      // Check parent directory for master CLAUDE.md
      const parentClaudeMd = path.join(path.dirname(projectDir), 'CLAUDE.md');
      try {
        if (parentClaudeMd !== projectClaudeMd) {
          const content = fs.readFileSync(parentClaudeMd, 'utf-8');
          parts.push('\n# Parent Project Context\n' + content);
        }
      } catch (e) { /* ignore */ }
    }

    return parts.join('\n\n');
  });

  // Log a chat event to a dashboard's logs.json
  ipcMain.handle('log-chat-event', async (_event, dashboardId, entry) => {
    const logsFile = path.join(DASHBOARDS_DIR, dashboardId, 'logs.json');
    let logs;
    try {
      logs = JSON.parse(fs.readFileSync(logsFile, 'utf-8'));
    } catch (e) {
      logs = { entries: [] };
    }
    logs.entries.push({
      timestamp: new Date().toISOString(),
      task_id: entry.task_id || null,
      agent: entry.agent || 'claude-chat',
      level: entry.level || 'info',
      message: entry.message,
      task_name: entry.task_name || 'Claude Chat',
    });
    fs.writeFileSync(logsFile, JSON.stringify(logs, null, 2));
    return { success: true };
  });

  ipcMain.handle('spawn-worker', async (_event, opts) => {
    console.log('[spawn-worker] Called with opts:', JSON.stringify({
      taskId: opts.taskId,
      model: opts.model,
      cliPath: opts.cliPath,
      projectDir: opts.projectDir,
      promptLen: opts.prompt ? opts.prompt.length : 0,
      dangerouslySkipPermissions: opts.dangerouslySkipPermissions,
    }));
    try {
      const result = ClaudeCodeService.spawnWorker(opts);
      console.log('[spawn-worker] Spawned PID:', result.pid);
      return result;
    } catch (err) {
      console.error('[spawn-worker] ERROR:', err.message);
      throw err;
    }
  });

  ipcMain.handle('kill-worker', async (_event, pid) => {
    return ClaudeCodeService.killWorker(pid);
  });

  ipcMain.handle('kill-all-workers', async () => {
    return ClaudeCodeService.killAllWorkers();
  });

  ipcMain.handle('get-active-workers', async () => {
    return ClaudeCodeService.getActiveWorkers();
  });

  // --- Commands handlers ---
  const CommandsService = require('./services/CommandsService');

  ipcMain.handle('list-commands', async (_event, commandsDir) => {
    return CommandsService.listCommands(commandsDir || undefined);
  });

  ipcMain.handle('get-command', async (_event, name, commandsDir) => {
    return CommandsService.getCommand(name, commandsDir || undefined);
  });

  ipcMain.handle('save-command', async (_event, name, content, commandsDir) => {
    return CommandsService.saveCommand(name, content, commandsDir || undefined);
  });

  ipcMain.handle('delete-command', async (_event, name, commandsDir) => {
    return CommandsService.deleteCommand(name, commandsDir || undefined);
  });

  ipcMain.handle('load-project-claude-md', async (_event, projectDir) => {
    return CommandsService.loadProjectClaudeMd(projectDir);
  });

  ipcMain.handle('list-project-commands', async (_event, projectDir) => {
    return CommandsService.listProjectCommands(projectDir);
  });

  // --- Orchestration handlers ---
  const SwarmOrchestrator = require('./services/SwarmOrchestrator');
  SwarmOrchestrator.init(broadcastFn);

  ipcMain.handle('start-swarm', async (_event, dashboardId, opts) => {
    return SwarmOrchestrator.startSwarm(dashboardId, opts);
  });

  ipcMain.handle('pause-swarm', async (_event, dashboardId) => {
    return SwarmOrchestrator.pauseSwarm(dashboardId);
  });

  ipcMain.handle('resume-swarm', async (_event, dashboardId) => {
    return SwarmOrchestrator.resumeSwarm(dashboardId);
  });

  ipcMain.handle('cancel-swarm', async (_event, dashboardId) => {
    return SwarmOrchestrator.cancelSwarm(dashboardId);
  });

  ipcMain.handle('retry-task', async (_event, dashboardId, taskId) => {
    return SwarmOrchestrator.retryTask(dashboardId, taskId);
  });

  ipcMain.handle('get-swarm-states', async () => {
    return SwarmOrchestrator.getSwarmStates();
  });

  // --- Conversation Handlers ---

  // GET conversations -> list-conversations
  ipcMain.handle('list-conversations', async () => {
    return { conversations: listConversations() };
  });

  // GET conversation -> load-conversation
  ipcMain.handle('load-conversation', async (_event, filename) => {
    const conv = loadConversation(filename);
    if (!conv) return { error: 'Conversation not found' };
    return conv;
  });

  // POST save-conversation
  ipcMain.handle('save-conversation', async (_event, conv) => {
    try {
      const result = saveConversation(conv);
      return { success: true, filename: result.filename, id: result.id };
    } catch (e) {
      return { success: false, error: e.message };
    }
  });

  // DELETE delete-conversation
  ipcMain.handle('delete-conversation', async (_event, filename) => {
    return deleteConversation(filename);
  });

  // PATCH rename-conversation
  ipcMain.handle('rename-conversation', async (_event, filename, newName) => {
    return renameConversation(filename, newName);
  });

  // --- 3. Set up file watchers with IPC broadcast ---

  const dashboards = listDashboards();

  // Start watchers for all existing dashboards
  for (const id of dashboards) {
    watchDashboard(id, broadcastFn);
  }

  // Start dashboards directory watcher (detects new/removed dashboards)
  startDashboardsWatcher(broadcastFn);

  // Start queue watcher
  startQueueWatcher(broadcastFn);

  // NOTE: Live reload is NOT started — it was for the web dev server, not needed in Electron

  // --- 4. Send initial data once the window is ready ---
  sendInitialData(getMainWindow, dashboards);
}

// ---------------------------------------------------------------------------
// Initial data push — mirrors the SSE /events connection handler
// ---------------------------------------------------------------------------

/**
 * Send initial data to the renderer once the window is available.
 * Mirrors the SSE /events endpoint's initial data burst.
 *
 * @param {Function} getMainWindow - returns the BrowserWindow
 * @param {string[]} dashboards - list of dashboard IDs
 */
function sendInitialData(getMainWindow, dashboards) {
  const trySend = () => {
    const win = getMainWindow();
    if (!win || win.isDestroyed()) {
      // Window not ready yet — retry shortly
      setTimeout(trySend, 100);
      return;
    }

    // Send list of all dashboards
    win.webContents.send('dashboards_list', { dashboards });

    // Send initial data for each dashboard
    for (const id of dashboards) {
      const init = readDashboardInit(id);
      if (init) {
        win.webContents.send('initialization', { dashboardId: id, ...init });
      }

      const progress = readDashboardProgress(id);
      if (Object.keys(progress).length > 0) {
        win.webContents.send('all_progress', { dashboardId: id, ...progress });
      }
    }

    // Send initial queue data
    const queueSummaries = listQueueSummaries();
    if (queueSummaries.length > 0) {
      win.webContents.send('queue_changed', { queue: queueSummaries });
    }
  };

  // Start trying after a short delay to let the window finish loading
  setTimeout(trySend, 200);
}

// ---------------------------------------------------------------------------
// Cleanup
// ---------------------------------------------------------------------------

/**
 * Stop all file watchers. Call on app quit.
 */
function stopWatchers() {
  stopAllWatchers();
}

module.exports = { registerIPCHandlers, stopWatchers };

// ClaudeView — Full Claude Code frontend embedded in the dashboard
// ES module. Renders a conversation view with prompt bar, tool call rendering,
// streaming output, and multi-session management with save/load/switch.

import { el } from '../utils/dom.js';
import { renderMarkdown } from '../utils/markdown.js';

export function renderClaudeView(opts) {
  var container = opts.container;
  container.innerHTML = '';

  var api = window.electronAPI;

  // Main wrapper
  var wrapper = el('div', { className: 'claude-view' });

  // ── Header bar ──────────────────────────────────────────────────────────────
  var header = el('div', { className: 'claude-view-header' });
  var headerTitle = el('span', { className: 'claude-view-title', text: 'Claude Code' });
  header.appendChild(headerTitle);

  var statusBadge = el('span', { className: 'claude-view-status', text: 'Ready' });
  header.appendChild(statusBadge);

  if (opts.onClose) {
    var closeBtn = el('button', { className: 'claude-view-close', text: '\u2715' });
    closeBtn.addEventListener('click', opts.onClose);
    header.appendChild(closeBtn);
  }
  wrapper.appendChild(header);

  // ── Session toolbar (between header and conversation) ───────────────────────
  var sessionToolbar = el('div', { className: 'claude-session-toolbar' });
  var newBtn = el('button', { className: 'claude-session-new-btn', text: '+ New' });
  sessionToolbar.appendChild(newBtn);
  wrapper.appendChild(sessionToolbar);

  // ── Conversation area ───────────────────────────────────────────────────────
  var conversation = el('div', { className: 'claude-conversation claude-view-conversation' });
  var welcomeMsg = el('div', { className: 'claude-system-msg' });
  welcomeMsg.textContent = 'Claude Code is ready. Type a message below to start.';
  conversation.appendChild(welcomeMsg);
  wrapper.appendChild(conversation);

  // ── Quick action chips ���──────────────────────────────────────────────────────
  var quickActions = el('div', { className: 'claude-quick-actions' });
  var actionDefs = [
    { label: 'New Swarm', fn: opts.onNewSwarm },
    { label: 'AI Plan',   fn: opts.onAIPlan   },
    { label: 'Launch',    fn: opts.onLaunch   },
    { label: 'Pause',     fn: opts.onPause    },
    { label: 'Cancel',    fn: opts.onCancel   },
  ];
  actionDefs.forEach(function (action) {
    if (!action.fn) return;
    var btn = el('button', { className: 'claude-quick-action-btn', text: action.label });
    btn.addEventListener('click', action.fn);
    quickActions.appendChild(btn);
  });
  wrapper.appendChild(quickActions);

  // ── Prompt bar ──────────────────────────────────────────────────────────────
  var promptBar = el('div', { className: 'claude-prompt-bar' });
  var promptInput = el('textarea', {
    className: 'claude-prompt-input',
    attrs: { placeholder: 'Ask Claude anything...', rows: '1' },
  });
  var sendBtn = el('button', { className: 'claude-send-btn', text: 'Send' });
  var modelSelect = el('select', { className: 'claude-model-select' });
  var models = [
    { value: 'sonnet', label: 'Sonnet' },
    { value: 'opus', label: 'Opus' },
    { value: 'haiku', label: 'Haiku' },
  ];
  models.forEach(function (m) {
    var opt = el('option', { text: m.label, attrs: { value: m.value } });
    modelSelect.appendChild(opt);
  });

  promptBar.appendChild(modelSelect);
  promptBar.appendChild(promptInput);
  promptBar.appendChild(sendBtn);
  wrapper.appendChild(promptBar);

  container.appendChild(wrapper);

  // ── Core worker state ───────────────────────────────────────────────────────
  var activeWorkerTaskId = null;
  var toolCallMap = {};
  var currentTextEl = null;
  var workerListener = null;
  var completeListener = null;
  var isProcessing = false;

  // ── Session state ───────────────────────────────────────────────────────────
  var currentConvId = null;          // id of active conversation
  var currentConvName = 'Session';   // name of active conversation
  var currentConvCreated = null;     // ISO string of creation time
  var currentMessages = [];          // [{role:'user'|'assistant', content:string, timestamp:string}]
  var pendingAssistantText = '';     // accumulates streaming text for the current turn

  var MAX_CHIPS = 6;

  // ── Session toolbar rendering ───────────────────────────────────────────────

  function refreshToolbar() {
    if (!api || !api.listConversations) return;
    api.listConversations().then(function (data) {
      var convs = (data && data.conversations) ? data.conversations : [];
      renderChips(convs);
    }).catch(function () {
      renderChips([]);
    });
  }

  function renderChips(convs) {
    // Remove all children after the "+ New" button
    var children = Array.prototype.slice.call(sessionToolbar.children);
    for (var i = 1; i < children.length; i++) {
      children[i].remove();
    }

    // Sort newest-first, cap at MAX_CHIPS
    var sorted = convs.slice().sort(function (a, b) {
      var ta = b.updated || b.created || '';
      var tb = a.updated || a.created || '';
      return ta > tb ? 1 : ta < tb ? -1 : 0;
    });

    var visible = sorted.slice(0, MAX_CHIPS);
    var hasOverflow = sorted.length > MAX_CHIPS;

    visible.forEach(function (conv) {
      var chip = makeChip(conv);
      sessionToolbar.appendChild(chip);
    });

    if (hasOverflow) {
      var overflowBtn = el('button', { className: 'claude-session-overflow', text: '\u00B7\u00B7\u00B7' });
      sessionToolbar.appendChild(overflowBtn);
    }
  }

  function makeChip(conv) {
    var isActive = conv.id === currentConvId;
    var chip = el('div', { className: 'claude-session-chip' + (isActive ? ' active' : '') });
    chip.dataset.convId = conv.id;

    // Active dot indicator
    var dot = el('span', { className: 'claude-session-dot' });
    chip.appendChild(dot);

    // Session name label
    var label = el('span', { className: 'claude-session-label' });
    label.textContent = conv.name || 'Session';
    chip.appendChild(label);

    // Delete button (visible on hover via CSS)
    var delBtn = el('button', { className: 'claude-session-delete', text: '\u00D7' });
    chip.appendChild(delBtn);

    // Click chip body (not delete button) to switch
    chip.addEventListener('click', function (e) {
      if (e.target === delBtn) return;
      switchToConversation(conv.id);
    });

    // Double-click label to rename inline
    label.addEventListener('dblclick', function (e) {
      e.stopPropagation();
      startInlineRename(chip, label, conv);
    });

    // Delete
    delBtn.addEventListener('click', function (e) {
      e.stopPropagation();
      deleteConversation(conv.id);
    });

    return chip;
  }

  function startInlineRename(chip, label, conv) {
    var input = el('input', { className: 'claude-session-label-input' });
    input.value = conv.name || 'Session';
    chip.replaceChild(input, label);
    input.focus();
    input.select();

    var saved = false;

    function saveRename() {
      if (saved) return;
      saved = true;
      var newName = input.value.trim() || 'Session';
      if (!api || !api.renameConversation) {
        chip.replaceChild(label, input);
        return;
      }
      api.renameConversation(conv.id, newName).then(function () {
        if (conv.id === currentConvId) {
          currentConvName = newName;
        }
        refreshToolbar();
      }).catch(function () {
        chip.replaceChild(label, input);
      });
    }

    input.addEventListener('keydown', function (e) {
      if (e.key === 'Enter') {
        e.preventDefault();
        saveRename();
      } else if (e.key === 'Escape') {
        saved = true; // prevent blur from saving
        chip.replaceChild(label, input);
      }
    });
    input.addEventListener('blur', saveRename);
  }

  // ── Conversation lifecycle ──────────────────────────────────────────────────

  function initConversations() {
    if (!api || !api.listConversations) return;
    api.listConversations().then(function (data) {
      var convs = (data && data.conversations) ? data.conversations : [];
      if (convs.length > 0) {
        // Load newest conversation
        var sorted = convs.slice().sort(function (a, b) {
          var ta = b.updated || b.created || '';
          var tb = a.updated || a.created || '';
          return ta > tb ? 1 : ta < tb ? -1 : 0;
        });
        loadConvIntoView(sorted[0].id);
      } else {
        createNewConversation();
      }
    }).catch(function () {
      createNewConversation();
    });
  }

  function loadConvIntoView(id) {
    if (!api || !api.loadConversation) return;
    api.loadConversation(id).then(function (data) {
      var conv = data && data.conversation ? data.conversation : data;
      if (!conv) return;

      currentConvId = conv.id;
      currentConvName = conv.name || 'Session';
      currentConvCreated = conv.created || new Date().toISOString();
      currentMessages = conv.messages || [];
      pendingAssistantText = '';

      // Clear and re-render history
      conversation.innerHTML = '';
      currentMessages.forEach(function (msg) {
        if (msg.role === 'user') {
          var userBubble = el('div', { className: 'claude-message claude-user' });
          var userText = el('div', { className: 'claude-message-text' });
          userText.textContent = msg.content;
          userBubble.appendChild(userText);
          conversation.appendChild(userBubble);
        } else if (msg.role === 'assistant') {
          var aMsg = el('div', { className: 'claude-message claude-assistant' });
          var aText = el('div', { className: 'claude-message-text' });
          aText.innerHTML = renderMarkdown(msg.content);
          aMsg.appendChild(aText);
          conversation.appendChild(aMsg);
        }
      });

      conversation.scrollTop = conversation.scrollHeight;
      refreshToolbar();
    }).catch(function () {
      refreshToolbar();
    });
  }

  function switchToConversation(id) {
    if (id === currentConvId) return;
    loadConvIntoView(id);
  }

  function createNewConversation() {
    if (!api || !api.createConversation) return;
    var name = 'Session ' + new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    api.createConversation(name).then(function (data) {
      var conv = data && data.conversation ? data.conversation : data;
      if (!conv) return;
      currentConvId = conv.id;
      currentConvName = conv.name || name;
      currentConvCreated = conv.created || new Date().toISOString();
      currentMessages = [];
      pendingAssistantText = '';

      conversation.innerHTML = '';
      var newWelcome = el('div', { className: 'claude-system-msg' });
      newWelcome.textContent = 'New conversation started. Type a message below.';
      conversation.appendChild(newWelcome);

      refreshToolbar();
    }).catch(function (err) {
      appendSystemMessage('Could not create conversation: ' + (err && err.message ? err.message : String(err)), true);
    });
  }

  function deleteConversation(id) {
    if (!api || !api.deleteConversation) return;
    api.deleteConversation(id).then(function () {
      if (id !== currentConvId) {
        refreshToolbar();
        return;
      }
      // Was active — switch to newest remaining or create new
      if (!api.listConversations) {
        currentConvId = null;
        currentMessages = [];
        conversation.innerHTML = '';
        createNewConversation();
        return;
      }
      api.listConversations().then(function (data) {
        var convs = (data && data.conversations) ? data.conversations : [];
        var remaining = convs.filter(function (c) { return c.id !== id; });
        if (remaining.length > 0) {
          var sorted = remaining.sort(function (a, b) {
            var ta = b.updated || b.created || '';
            var tb = a.updated || a.created || '';
            return ta > tb ? 1 : ta < tb ? -1 : 0;
          });
          loadConvIntoView(sorted[0].id);
        } else {
          currentConvId = null;
          currentMessages = [];
          conversation.innerHTML = '';
          createNewConversation();
        }
      });
    }).catch(function () {
      refreshToolbar();
    });
  }

  // ── New button handler ──────────────────────────────────────────────────────
  newBtn.addEventListener('click', createNewConversation);

  // ── Textarea auto-resize + keyboard shortcut ────────────────────────────────
  promptInput.addEventListener('input', function () {
    promptInput.style.height = 'auto';
    var scrollH = promptInput.scrollHeight;
    promptInput.style.height = Math.min(scrollH, 150) + 'px';
  });

  promptInput.addEventListener('keydown', function (e) {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  });

  sendBtn.addEventListener('click', sendMessage);

  // ── Send message ────────────────────────────────────────────────────────────
  function sendMessage() {
    var text = promptInput.value.trim();
    if (!text || isProcessing || !api) return;

    // Render user bubble
    var userMsg = el('div', { className: 'claude-message claude-user' });
    var userText = el('div', { className: 'claude-message-text' });
    userText.textContent = text;
    userMsg.appendChild(userText);
    conversation.appendChild(userMsg);

    // Track user message in currentMessages
    currentMessages.push({ role: 'user', content: text, timestamp: new Date().toISOString() });

    // Reset pending assistant text
    pendingAssistantText = '';

    promptInput.value = '';
    promptInput.style.height = 'auto';
    isProcessing = true;
    statusBadge.textContent = 'Thinking...';
    statusBadge.classList.add('active');
    sendBtn.disabled = true;

    activeWorkerTaskId = '_claude_' + Date.now();
    toolCallMap = {};
    currentTextEl = null;

    // Build multi-turn prompt with prior context
    var priorMessages = currentMessages.slice(0, currentMessages.length - 1);
    var fullPrompt = text;
    if (priorMessages.length > 0) {
      var transcript = priorMessages.map(function (m) {
        return (m.role === 'user' ? 'User' : 'Assistant') + ': ' + m.content;
      }).join('\n');
      fullPrompt = '[Prior conversation context:\n' + transcript + ']\n\n[Current message:]\n' + text;
    }

    api.getSettings().then(function (settings) {
      var model = modelSelect.value || settings.defaultModel || 'sonnet';
      return api.spawnWorker({
        taskId: activeWorkerTaskId,
        prompt: fullPrompt,
        model: model,
        cliPath: settings.claudeCliPath || null,
        dangerouslySkipPermissions: settings.dangerouslySkipPermissions || false,
        projectDir: settings.activeProjectPath || null,
      });
    }).catch(function (err) {
      appendSystemMessage('Error: ' + (err && err.message ? err.message : String(err)), true);
      finishProcessing();
    });
  }

  // ── Text rendering helpers ──────────────────────────────────────────────────
  function flushText() { currentTextEl = null; }

  function appendTextContent(text) {
    if (!currentTextEl) {
      currentTextEl = el('div', { className: 'claude-message claude-assistant' });
      var textContent = el('div', { className: 'claude-message-text' });
      currentTextEl.appendChild(textContent);
      conversation.appendChild(currentTextEl);
      currentTextEl._textEl = textContent;
      currentTextEl._rawText = '';
    }
    currentTextEl._rawText += text;
    currentTextEl._textEl.innerHTML = renderMarkdown(currentTextEl._rawText);
    // Accumulate into pendingAssistantText for later save
    pendingAssistantText += text;
  }

  function appendSystemMessage(text, isError) {
    flushText();
    var msg = el('div', { className: 'claude-system-msg' + (isError ? ' claude-error' : '') });
    msg.textContent = text;
    conversation.appendChild(msg);
  }

  function renderToolCall(block) {
    flushText();
    var wrapper2 = el('div', { className: 'claude-tool-call' });
    var hdr = el('div', { className: 'claude-tool-header' });
    var icon = el('span', { className: 'claude-tool-icon', text: '\u2699' });
    var name = el('span', { className: 'claude-tool-name', text: block.name });
    var toggle = el('span', { className: 'claude-tool-toggle', text: '\u25B6' });
    hdr.appendChild(icon); hdr.appendChild(name); hdr.appendChild(toggle);
    wrapper2.appendChild(hdr);
    var bodyEl = el('div', { className: 'claude-tool-body', style: { display: 'none' } });
    if (block.input) {
      var inputLabel = el('div', { className: 'claude-tool-label', text: 'Input:' });
      bodyEl.appendChild(inputLabel);
      var inputPre = el('pre', { className: 'claude-tool-input' });
      try {
        inputPre.textContent = typeof block.input === 'string' ? block.input : JSON.stringify(block.input, null, 2);
      } catch (e) { inputPre.textContent = String(block.input); }
      bodyEl.appendChild(inputPre);
    }
    wrapper2.appendChild(bodyEl);
    hdr.addEventListener('click', function () {
      var isOpen = bodyEl.style.display !== 'none';
      bodyEl.style.display = isOpen ? 'none' : 'block';
      toggle.textContent = isOpen ? '\u25B6' : '\u25BC';
      wrapper2.classList.toggle('expanded', !isOpen);
    });
    wrapper2._toolId = block.id || null;
    wrapper2._body = bodyEl;
    conversation.appendChild(wrapper2);
    if (block.id) toolCallMap[block.id] = wrapper2;
  }

  function appendToolResult(toolUseId, content) {
    flushText();
    var target = toolUseId ? toolCallMap[toolUseId] : null;
    var bodyEl = target ? target._body : null;
    var resultLabel = el('div', { className: 'claude-tool-label claude-tool-result-label', text: 'Result:' });
    var resultPre = el('pre', { className: 'claude-tool-result' });
    if (typeof content === 'string') {
      resultPre.textContent = content;
    } else if (Array.isArray(content)) {
      resultPre.textContent = content.map(function (b) { return b.type === 'text' ? b.text : JSON.stringify(b, null, 2); }).join('\n');
    } else {
      try { resultPre.textContent = JSON.stringify(content, null, 2); } catch (e) { resultPre.textContent = String(content); }
    }
    if (bodyEl) {
      bodyEl.appendChild(resultLabel); bodyEl.appendChild(resultPre);
    } else {
      var standalone = el('div', { className: 'claude-tool-result-standalone' });
      standalone.appendChild(resultLabel); standalone.appendChild(resultPre);
      conversation.appendChild(standalone);
    }
  }

  // ── Finish processing + auto-save ───────────────────────────────────────────
  function finishProcessing() {
    // Save accumulated assistant text to message history
    if (pendingAssistantText) {
      currentMessages.push({ role: 'assistant', content: pendingAssistantText, timestamp: new Date().toISOString() });
    }
    pendingAssistantText = '';

    // Auto-save conversation
    if (api && currentConvId && api.saveConversation) {
      api.saveConversation({
        id: currentConvId,
        name: currentConvName,
        messages: currentMessages,
        created: currentConvCreated || new Date().toISOString(),
        updated: new Date().toISOString(),
      }).catch(function () { /* silent */ });
    }

    isProcessing = false;
    statusBadge.textContent = 'Ready';
    statusBadge.classList.remove('active');
    sendBtn.disabled = false;
    activeWorkerTaskId = null;
    flushText();
    promptInput.focus();
  }

  // ── Event listeners for worker output ──────────────────────────────────────
  if (api) {
    workerListener = api.on('worker-output', function (data) {
      if (!activeWorkerTaskId || data.taskId !== activeWorkerTaskId) return;
      var lines = data.chunk.split('\n');
      for (var i = 0; i < lines.length; i++) {
        var line = lines[i].trim();
        if (!line) continue;
        try {
          var parsed = JSON.parse(line);
          if (parsed.type === 'assistant' && parsed.content) {
            for (var c = 0; c < parsed.content.length; c++) {
              var block = parsed.content[c];
              if (block.type === 'text') appendTextContent(block.text);
              else if (block.type === 'tool_use') renderToolCall(block);
            }
          } else if (parsed.type === 'content_block_start') {
            if (parsed.content_block && parsed.content_block.type === 'tool_use') renderToolCall(parsed.content_block);
          } else if (parsed.type === 'tool_result') {
            appendToolResult(parsed.tool_use_id, parsed.content);
          } else if (parsed.type === 'result') {
            flushText();
            if (parsed.result) {
              var resultMsg = el('div', { className: 'claude-message claude-assistant' });
              var resultText = el('div', { className: 'claude-message-text' });
              resultText.innerHTML = renderMarkdown(parsed.result);
              resultMsg.appendChild(resultText);
              conversation.appendChild(resultMsg);
              // Capture result text for message history
              pendingAssistantText += parsed.result;
            }
          } else if (parsed.type === 'system') {
            appendSystemMessage(parsed.message || JSON.stringify(parsed));
          }
        } catch (e) {
          appendTextContent(line + '\n');
        }
      }
      conversation.scrollTop = conversation.scrollHeight;
    });

    completeListener = api.on('worker-complete', function (data) {
      if (!activeWorkerTaskId || data.taskId !== activeWorkerTaskId) return;
      if (data.errorOutput) appendSystemMessage('[stderr] ' + data.errorOutput, true);
      finishProcessing();
    });

    // Initialize: load newest conversation or create new
    initConversations();
  }

  // ── Public controller ───────────────────────────────────────────────────────
  return {
    clear: function () { conversation.innerHTML = ''; toolCallMap = {}; currentTextEl = null; },
    destroy: function () {
      if (api && workerListener) api.off('worker-output', workerListener);
      if (api && completeListener) api.off('worker-complete', completeListener);
      wrapper.remove();
    },
    getElement: function () { return wrapper; },
  };
}

